export const particleVertexShader = `
uniform float uTime;
uniform float uSize;
uniform float uPulsate;
uniform float uPulsateSpeed;
attribute float scale;
varying vec3 vColor;
void main() {
  vColor = color;
  vec4 modelPosition = modelMatrix * vec4(position, 1.0);
  if (uPulsate > 0.5) {
    float pulsateValue = sin(uTime * uPulsateSpeed + position.x * 10.0) * 0.5 + 0.5;
    modelPosition.y += pulsateValue * 0.02;
  }
  vec4 viewPosition = viewMatrix * modelPosition;
  vec4 projectedPosition = projectionMatrix * viewPosition;
  gl_Position = projectedPosition;
  gl_PointSize = uSize * scale * (1.0 / -viewPosition.z);
}`;

export const particleFragmentShader = `
varying vec3 vColor;
uniform float uGlow;
uniform float uDensity;
void main() {
  float distanceToCenter = distance(gl_PointCoord, vec2(0.5));
  float strength = uGlow / distanceToCenter - (uGlow * 2.0);
  strength = max(0.0, strength);
  gl_FragColor = vec4(vColor, strength * uDensity);
}`;

interface InteractionState {
  mouse: { x: number; y: number };
  isDragging: boolean;
  previousMouse: { x: number; y: number };
  targetRotation: { x: number; y: number };
  currentRotation: { x: number; y: number };
  currentTilt: { x: number; y: number };
  targetZoom: number;
  currentZoom: number;
}

interface InteractionOptions {
  enableDrag: boolean;
  enableZoom: boolean;
  enableTouch: boolean;
  minZoom: number;
  maxZoom: number;
}

export function useGalaxyInteractions(
  el: HTMLElement,
  state: InteractionState,
  options: InteractionOptions,
): () => void {
  let touchStartDistance = 0;
  let touchStartZoom = 3;

  const onMouseMove = (e: MouseEvent) => {
    if (state.isDragging) return;
    const r = el.getBoundingClientRect();
    state.mouse.x = ((e.clientX - r.left) / r.width) * 2 - 1;
    state.mouse.y = -(((e.clientY - r.top) / r.height) * 2 - 1);
  };

  const onMouseLeave = () => {
    if (!state.isDragging) {
      state.mouse.x = 0;
      state.mouse.y = 0;
    }
  };

  const onMouseDown = (e: MouseEvent) => {
    if (!options.enableDrag) return;
    state.isDragging = true;
    state.previousMouse.x = e.clientX;
    state.previousMouse.y = e.clientY;
    el.style.cursor = 'grabbing';
  };

  const onMouseMoveGlobal = (e: MouseEvent) => {
    if (!state.isDragging || !options.enableDrag) return;
    state.targetRotation.y += (e.clientX - state.previousMouse.x) * 0.005;
    state.targetRotation.x += (e.clientY - state.previousMouse.y) * 0.005;
    state.targetRotation.x = Math.max(
      -Math.PI / 2,
      Math.min(Math.PI / 2, state.targetRotation.x),
    );
    state.previousMouse.x = e.clientX;
    state.previousMouse.y = e.clientY;
  };

  const onMouseUp = () => {
    if (!options.enableDrag) return;
    state.isDragging = false;
    el.style.cursor = options.enableDrag ? 'grab' : 'default';
  };

  const onWheel = (e: WheelEvent) => {
    if (!options.enableZoom) return;
    e.preventDefault();
    state.targetZoom += e.deltaY * 0.001;
    state.targetZoom = Math.max(
      options.minZoom,
      Math.min(options.maxZoom, state.targetZoom),
    );
  };

  const getTouchDist = (ts: TouchList) => {
    if (ts.length < 2) return 0;
    const dx = ts[0]!.clientX - ts[1]!.clientX;
    const dy = ts[0]!.clientY - ts[1]!.clientY;
    return Math.sqrt(dx * dx + dy * dy);
  };

  const onTouchStart = (e: TouchEvent) => {
    if (!options.enableTouch) return;
    if (e.touches.length === 2) {
      touchStartDistance = getTouchDist(e.touches);
      touchStartZoom = state.targetZoom;
    } else if (e.touches.length === 1 && options.enableDrag) {
      state.isDragging = true;
      state.previousMouse.x = e.touches[0]!.clientX;
      state.previousMouse.y = e.touches[0]!.clientY;
    }
  };

  const onTouchMove = (e: TouchEvent) => {
    if (!options.enableTouch) return;
    if (e.touches.length === 2 && options.enableZoom) {
      e.preventDefault();
      const d = getTouchDist(e.touches);
      state.targetZoom = Math.max(
        options.minZoom,
        Math.min(options.maxZoom, touchStartZoom * (touchStartDistance / d)),
      );
    } else if (
      e.touches.length === 1 &&
      state.isDragging &&
      options.enableDrag
    ) {
      state.targetRotation.y +=
        (e.touches[0]!.clientX - state.previousMouse.x) * 0.005;
      state.targetRotation.x +=
        (e.touches[0]!.clientY - state.previousMouse.y) * 0.005;
      state.targetRotation.x = Math.max(
        -Math.PI / 2,
        Math.min(Math.PI / 2, state.targetRotation.x),
      );
      state.previousMouse.x = e.touches[0]!.clientX;
      state.previousMouse.y = e.touches[0]!.clientY;
    }
  };

  const onTouchEnd = () => {
    if (options.enableTouch) {
      state.isDragging = false;
      touchStartDistance = 0;
    }
  };

  el.addEventListener('mousemove', onMouseMove);
  el.addEventListener('mouseleave', onMouseLeave);
  el.addEventListener('mousedown', onMouseDown);
  document.addEventListener('mousemove', onMouseMoveGlobal);
  document.addEventListener('mouseup', onMouseUp);
  el.addEventListener('wheel', onWheel, { passive: false });
  el.addEventListener('touchstart', onTouchStart, { passive: false });
  el.addEventListener('touchmove', onTouchMove, { passive: false });
  el.addEventListener('touchend', onTouchEnd);
  el.style.cursor = options.enableDrag ? 'grab' : 'default';

  return () => {
    el.removeEventListener('mousemove', onMouseMove);
    el.removeEventListener('mouseleave', onMouseLeave);
    el.removeEventListener('mousedown', onMouseDown);
    document.removeEventListener('mousemove', onMouseMoveGlobal);
    document.removeEventListener('mouseup', onMouseUp);
    el.removeEventListener('wheel', onWheel);
    el.removeEventListener('touchstart', onTouchStart);
    el.removeEventListener('touchmove', onTouchMove);
    el.removeEventListener('touchend', onTouchEnd);
  };
}

import * as THREE from 'three';
import type { ParticleGalaxyBlendMode } from '~/types/components';
import { particleVertexShader, particleFragmentShader } from './shaders';

interface ParticleConfig {
  particleCount: number;
  particleSize: number;
  spiralArms: number;
  colors: [string, string, string];
  blendMode: ParticleGalaxyBlendMode;
  spread: number;
  density: number;
  glow: number;
  centerConcentration: number;
  pulsate: boolean;
  pulsateSpeed: number;
}

export function createGalaxyParticles(config: ParticleConfig) {
  const geometry = new THREE.BufferGeometry();
  const positions = new Float32Array(config.particleCount * 3);
  const colors = new Float32Array(config.particleCount * 3);
  const scales = new Float32Array(config.particleCount);
  const palette = config.colors.map((c) => new THREE.Color(c));
  const rStr = 0.3 * (config.spread / 2.5);
  const rSign = () => (Math.random() < 0.5 ? 1 : -1);

  for (let i = 0; i < config.particleCount; i++) {
    const i3 = i * 3;
    const radius =
      Math.pow(Math.random(), config.centerConcentration) * config.spread;
    const spin = radius * config.spiralArms;
    const branch =
      ((i % config.spiralArms) / config.spiralArms) * Math.PI * 2 + spin;
    positions[i3] =
      Math.cos(branch) * radius + Math.pow(Math.random(), 3) * rSign() * rStr;
    positions[i3 + 1] = Math.pow(Math.random(), 3) * rSign() * rStr;
    positions[i3 + 2] =
      Math.sin(branch) * radius + Math.pow(Math.random(), 3) * rSign() * rStr;
    const mixed = palette[i % 3]!.clone();
    const cd = radius / config.spread;
    if (config.blendMode === 'normal')
      mixed.lerp(new THREE.Color('#000000'), cd * 0.5);
    else mixed.lerp(new THREE.Color('#ffffff'), 1 - cd);
    colors[i3] = mixed.r;
    colors[i3 + 1] = mixed.g;
    colors[i3 + 2] = mixed.b;
    scales[i] = Math.random();
  }

  geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  geometry.setAttribute('scale', new THREE.BufferAttribute(scales, 1));

  const material = new THREE.ShaderMaterial({
    uniforms: {
      uTime: { value: 0 },
      uSize: { value: config.particleSize * 100 },
      uGlow: { value: config.glow / 100 },
      uDensity: { value: config.density },
      uPulsate: { value: config.pulsate ? 1.0 : 0.0 },
      uPulsateSpeed: { value: config.pulsateSpeed },
    },
    vertexShader: particleVertexShader,
    fragmentShader: particleFragmentShader,
    transparent: true,
    depthWrite: false,
    vertexColors: true,
    blending:
      config.blendMode === 'additive'
        ? THREE.AdditiveBlending
        : THREE.NormalBlending,
  });

  const points = new THREE.Points(geometry, material);
  return { geometry, material, points };
}
